sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading || newValue === '') return;

    var extendingDate = new Date(newValue);
    var expiryDateStr = g_form.getValue('warranty_expiring_at');

    if (!expiryDateStr) return;

    var expiryDate = new Date(expiryDateStr);

    if (extendingDate <= expiryDate) {
        // Delay to allow clearing to finish before showing the message
        setTimeout(function() {
            g_form.showFieldMsg('warranty_extending_date',
                'Warranty Extending date must be later than Warranty Expiring at date.',
                'error');
        }, 100);

        g_form.clearValue('warranty_extending_date');
    } else {
        g_form.hideFieldMsg('warranty_extending_date');
    }
}
